CREATE TABLE IF NOT EXISTS public.copilot_button_clicks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE, context_type text NOT NULL, context_subtype text, action_key text NOT NULL, action_label text NOT NULL, customer_id uuid, job_id uuid, created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX IF NOT EXISTS idx_cbc_user_ctx ON public.copilot_button_clicks (user_id, context_type, context_subtype, created_at DESC); ALTER TABLE public.copilot_button_clicks ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS cbc_select ON public.copilot_button_clicks; CREATE POLICY cbc_select ON public.copilot_button_clicks FOR SELECT USING (auth.uid() = user_id); DROP POLICY IF EXISTS cbc_insert ON public.copilot_button_clicks; CREATE POLICY cbc_insert ON public.copilot_button_clicks FOR INSERT WITH CHECK (auth.uid() = user_id);